/**
 * Network-first caching strategy for the SW's static-asset path, extracted for
 * testability (same pattern as service-worker-api-proxy, story 132).
 *
 * Story 213 (the 2026-06-11/12 deploy-staleness incident): a GitHub Pages
 * deploy deletes the previous build's hashed chunks, so a stale cached app
 * shell requests URLs the network now answers with 404 (the SPA-fallback page
 * body). The old strategy trusted any network *response* — only a thrown fetch
 * fell back to cache — so the precached chunk sat unused while the boot died
 * on a 404'd script. Two corrections:
 *
 * 1. A non-ok response for a hashed asset falls back to the cached copy — the
 *    SW that cached the shell also precached the manifest chunks that shell
 *    references, and runtime-fetched assets the manifest misses (worker
 *    chunks, sqlite wasm — see story 216) sit in the same cache from the
 *    boots that used them.
 * 2. Non-ok responses are never written to the cache.
 */

export interface StaticCacheDeps {
    fetchImpl: typeof fetch;
    cacheMatch: (request: Request) => Promise<Response | undefined>;
    cachePut: (request: Request, response: Response) => Promise<void>;
    /** Whether a non-ok network response for this request may serve from cache. */
    isCacheFallbackEligible: (request: Request) => boolean;
}

/**
 * Hashed-asset predicate for the fallback eligibility: same-origin GETs under
 * `${basePath}assets/`. Hashed filenames make these immutable — a cached copy
 * is bytewise the deployed file, so serving it over a 404 is always correct.
 * Non-hashed statics (style.css, manifest.json) stay network-authoritative.
 */
export function isHashedAssetRequest(request: Request, origin: string, basePath: string): boolean {
    if (request.method !== 'GET') return false;
    const url = new URL(request.url);
    return url.origin === origin && url.pathname.startsWith(`${basePath}assets/`);
}

export async function networkFirstStatic(request: Request, deps: StaticCacheDeps): Promise<Response> {
    // Destructure before calling: `deps.fetchImpl(request)` would bind `this`
    // to the deps object, and the browser-native fetch throws "Illegal
    // invocation" for any `this` other than undefined or the global.
    const { fetchImpl } = deps;
    try {
        const response = await fetchImpl(request);
        if (response.ok) {
            void deps.cachePut(request, response.clone());
            return response;
        }
        if (deps.isCacheFallbackEligible(request)) {
            const cached = await deps.cacheMatch(request);
            if (cached) {
                return cached;
            }
        }
        return response;
    } catch {
        const cached = await deps.cacheMatch(request);
        return cached ?? new Response('Network error happened', {
            status: 408,
            headers: { 'Content-Type': 'text/plain' },
        });
    }
}

/**
 * Cache a successful navigation response under the navigation URL AND the
 * app-shell key. The shell fallback (`appShellResponse`) only ever reads the
 * index.html key, which used to be written exclusively at SW install — so the
 * cached shell stayed frozen at install vintage and kept referencing chunks
 * long after deploys deleted them. Refreshing it on every successful
 * navigation keeps the offline shell at most one deploy old.
 *
 * Takes ownership of `response` (callers pass a clone).
 */
export async function cacheNavigationSuccess(
    request: Request,
    response: Response,
    cachePut: StaticCacheDeps['cachePut'],
    indexHtmlUrl: string,
): Promise<void> {
    await cachePut(request, response.clone());
    await cachePut(new Request(indexHtmlUrl), response);
}
