import {
    networkFirstApi,
    proxyApiRequestToClient as proxyApiRequestToClientCore,
} from './services/offline/service-worker-api-proxy.js';
import {
    handleNotificationClick,
    showPushNotification,
} from './services/sw-notifications.js';
import { handleClientLogSyncEvent } from './services/debug/client-log-sync-handler.js';
import { handleImageUploadSyncEvent } from './services/offline/image-upload-sync-handler.js';
import { handleEstimateSubmitSyncEvent } from './services/offline/estimate-submit-sync-handler.js';
import {
    IMAGE_CACHE_NAME,
    cacheFirstImage,
    isImageServeUrl,
} from './services/offline/service-worker-image-cache.js';
import {
    cacheNavigationSuccess,
    isHashedAssetRequest,
    networkFirstStatic,
} from './services/offline/service-worker-static-cache.js';
import { API_URL, PI_GATEWAY_URL } from './config.js';
import {
    createSnapshotMarkDirtyMessage,
    createSnapshotRefreshMessage,
} from './services/sw-messages.js';

const SNAPSHOT_REFRESH_TAG = 'snapshot-refresh';
const SNAPSHOT_REFRESH_MIN_INTERVAL_MS = 60 * 60 * 1000; // 1 hour

const CACHE_NAME = 'motivation-pwa-v3';
const BASE_PATH = import.meta.env.BASE_URL;

const BUILD_MANIFEST_PATH = `${BASE_PATH}asset-manifest.json`;
const ASSETS_TO_CACHE = [
    BASE_PATH,
    `${BASE_PATH}index.html`,
    `${BASE_PATH}icon.png`,
    `${BASE_PATH}manifest.json`,
];

interface BuildManifestChunk {
    file: string;
    css?: string[];
    assets?: string[];
}

type BuildManifest = Record<string, BuildManifestChunk>;

const toAppPath = (assetPath: string): string => {
    return new URL(assetPath, new URL(BASE_PATH, self.location.origin)).pathname;
};

const getPrecachePaths = (buildManifest: BuildManifest): string[] => {
    const assetPaths = new Set<string>([...ASSETS_TO_CACHE, BUILD_MANIFEST_PATH]);

    for (const chunk of Object.values(buildManifest)) {
        const paths = [chunk.file, ...(chunk.css ?? []), ...(chunk.assets ?? [])];

        for (const path of paths) {
            // Skip the service-worker itself — it doesn't need to cache itself.
            if (path === 'service-worker.js') continue;

            assetPaths.add(toAppPath(path));
            // Note: do NOT add .map files — they are debug artifacts that may
            // not be deployed and would cause cache.addAll() to fail atomically.
        }
    }

    return [...assetPaths];
};

const addCoiHeaders = (request: Request, response: Response): Response => {
    if (response.status === 0 || response.type === 'opaque') {
        return response;
    }
    const newHeaders = new Headers(response.headers);
    newHeaders.set('Cross-Origin-Embedder-Policy', 'require-corp');
    if (request.mode === 'navigate') {
        newHeaders.set('Cross-Origin-Opener-Policy', 'same-origin');
    }
    return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: newHeaders,
    });
};

const putInCache: (request: Request, response: Response) => Promise<void> = async (request: Request, response: Response) => {
    if (request.method !== "GET") {
        return;
    }
    try {
        const cache = await caches.open(CACHE_NAME);
        await cache.put(request, response);
    } catch (error) {
        console.log("request cannot be cached", request, error);
    }
};

// Network-first with the story-213 deploy-staleness corrections: non-ok
// answers for hashed assets fall back to the precached copy, and non-ok
// responses are never cached. Strategy logic lives in
// service-worker-static-cache.ts so it is unit-testable.
const networkFirst = async (request: Request): Promise<Response> => {
    const response = await networkFirstStatic(request, {
        fetchImpl: fetch,
        cacheMatch: async (req) => caches.match(req),
        cachePut: putInCache,
        isCacheFallbackEligible: (req) => isHashedAssetRequest(req, self.location.origin, BASE_PATH),
    });
    return addCoiHeaders(request, response);
};

const appShellResponse = async (request: Request): Promise<Response> => {
    const indexRequest = new Request(`${self.location.origin}${BASE_PATH}index.html`);
    const cachedResponse = await caches.match(indexRequest);
    const response = cachedResponse ?? await fetch(indexRequest);
    return addCoiHeaders(request, response);
};

const proxyApiRequestToClientImpl = (request: Request): Promise<Response> => {
    return proxyApiRequestToClientCore(request, async () => {
        const clients = await self.clients.matchAll({ type: 'window', includeUncontrolled: true });
        return [...clients];
    });
};

const networkFirstApiForSw = async (request: Request): Promise<Response> => {
    console.debug('[SYNC-DEBUG][sw] networkFirstApi for:', request.method, request.url);
    const response = await networkFirstApi(request, fetch, proxyApiRequestToClientImpl);
    console.debug('[SYNC-DEBUG][sw] networkFirstApi result:', response.status, 'for', request.url);
    return response;
};

const isApiRequest = (request: Request): boolean => {
    const url = new URL(request.url);

    // 1. Explicitly exclude Pi Gateway requests.
    // Use startsWith on the full URL to handle cases where Gateway and API share an origin.
    if (url.href.startsWith(PI_GATEWAY_URL)) return false;

    // 2. Check if it targets the API origin.
    const apiOrigin = new URL(API_URL).origin;
    if (url.origin !== apiOrigin) return false;

    // 3. Only intercept requests targeting the /api/ path.
    // If API_URL has a path (e.g. /api), we should check against that.
    const apiPathname = new URL(API_URL).pathname;
    const normalizedApiPath = apiPathname.endsWith('/') ? apiPathname : apiPathname + '/';

    if (!url.pathname.startsWith(normalizedApiPath)) return false;

    console.debug('[SYNC-DEBUG][sw] Detected API request:', request.method, request.url);
    return true;
};

self.addEventListener("fetch", (event: FetchEvent) => {
    const url = new URL(event.request.url);

    if (isApiRequest(event.request)) {
        // Image GETs at /api/files/images/<scope>/<uuidv7>/<variant> are
        // content-stable; cache them aggressively in a dedicated cache so
        // thumbnails work offline once seen. POST /api/files/images and
        // anything else falls through to network-first. Story 124.
        //
        // The cache-miss network fetch goes through `networkFirstApiForSw`
        // (story 132) so an offline miss falls through to the proxy chain
        // rather than rejecting with a bare TypeError.
        if (event.request.method === 'GET' && isImageServeUrl(event.request.url)) {
            event.respondWith(cacheFirstImage(event.request, networkFirstApiForSw));
            return;
        }

        event.respondWith((async () => {
            const response = await networkFirstApiForSw(event.request);
            // Story 133 trigger 1 — central markDirty chokepoint.
            // A successful non-GET API response means the server DB may
            // have changed; tell clients to schedule a refresh check.
            // The main-thread bridge debounces (~1s) so a burst of writes
            // collapses to one refresh.
            if (response.ok && event.request.method !== 'GET' && event.request.method !== 'HEAD') {
                await postSnapshotMarkDirty();
            }
            return response;
        })());
        return;
    }

    if (url.origin !== self.location.origin) {
        // Don't intercept cross-origin requests (e.g. Open Food Facts API)
        return;
    }

    if (event.request.mode === 'navigate') {
        event.respondWith((async () => {
            try {
                const response = await fetch(event.request);
                if (response.ok) {
                    // Refresh the app-shell key too (story 213): the shell
                    // fallback only reads index.html, which install alone
                    // wrote — leaving offline boots a stale deploy behind.
                    void cacheNavigationSuccess(
                        event.request,
                        response.clone(),
                        putInCache,
                        `${self.location.origin}${BASE_PATH}index.html`,
                    );
                    return addCoiHeaders(event.request, response);
                }
            } catch {
                // Fall back to the cached app shell below.
            }

            return appShellResponse(event.request);
        })());
        return;
    }

    event.respondWith(
        networkFirst(event.request),
    );
});

// Opt out of Chrome's ServiceWorkerAutoPreload (crbug.com/466790291).
// A Chrome-for-Android regression (M143+) breaks the initial navigation's
// fetch event when the SW is not yet running — i.e. exactly a PWA cold
// resume — leaving the standalone window permanently blank (black screen,
// zero document load; diagnosed via boot breadcrumbs, design_log #157).
// Registering a catch-all static route with source 'fetch-event' disables
// the auto-preload race. The Chromium engineer on the issue confirmed this
// opt-out is safe to keep permanently, even once the feature is fixed.
self.addEventListener('install', (event: ExtendableEvent) => {
    const e = event as ExtendableEvent & {
        addRoutes?: (rules: { condition: { urlPattern: object }; source: string }) => Promise<void>;
    };
    const URLPatternCtor = (globalThis as { URLPattern?: new (init: object) => object }).URLPattern;
    if (typeof e.addRoutes === 'function' && URLPatternCtor) {
        // new URLPattern({}) matches every request on every origin — the SW's
        // fetch handler also intercepts cross-origin API requests, so the
        // opt-out must not be limited to same-origin URLs.
        void e.addRoutes({
            condition: { urlPattern: new URLPatternCtor({}) },
            source: 'fetch-event',
        }).catch((error: unknown) => {
            console.warn('[SW] ServiceWorkerAutoPreload opt-out failed:', error);
        });
    }
});

self.addEventListener("install", async (event: ExtendableEvent) => {
    const preCache = async () => {
        const cache = await caches.open(CACHE_NAME);
        const indexRequest = new Request(`${self.location.origin}${BASE_PATH}index.html`);
        const buildManifestRequest = new Request(`${self.location.origin}${BUILD_MANIFEST_PATH}`);
        const [indexResponse, buildManifestResponse] = await Promise.all([
            fetch(indexRequest, { cache: 'no-cache' }),
            fetch(buildManifestRequest, { cache: 'no-cache' }),
        ]);

        if (!indexResponse.ok) {
            throw new Error(`Failed to fetch app shell: ${indexResponse.status}`);
        }

        if (!buildManifestResponse.ok) {
            throw new Error(`Failed to fetch build manifest: ${buildManifestResponse.status}`);
        }

        const buildManifest = await buildManifestResponse.clone().json() as BuildManifest;
        const precachePaths = getPrecachePaths(buildManifest);

        await cache.put(indexRequest, indexResponse.clone());
        await cache.put(buildManifestRequest, buildManifestResponse);

        const requestsToPrecache = precachePaths
            .filter((path) => path !== `${BASE_PATH}index.html` && path !== BUILD_MANIFEST_PATH)
            .map((path) => new Request(`${self.location.origin}${path}`));

        // Use individual fetch+put instead of cache.addAll() to avoid a single
        // failed request aborting the entire SW install (cache.addAll is all-or-nothing).
        await Promise.all(requestsToPrecache.map(async (request) => {
            try {
                const response = await fetch(request);
                if (response.ok) {
                    await cache.put(request, response);
                } else {
                    console.warn(`[SW] Precache skipped (${response.status}):`, request.url);
                }
            } catch (err) {
                console.warn('[SW] Precache fetch failed:', request.url, err);
            }
        }));
    }
    event.waitUntil(preCache().then(() => self.skipWaiting()));
});


const KEPT_CACHES = new Set<string>([CACHE_NAME, IMAGE_CACHE_NAME]);

self.addEventListener("activate", (event: ExtendableEvent) => {
    event.waitUntil((async () => {
        // Delete any legacy caches from older SW versions. The image cache
        // (motivation-images-v1) is kept across SW upgrades — its keys are
        // content-stable, so eviction is the browser's job.
        const cacheNames = await caches.keys();
        await Promise.all(
            cacheNames
                .filter(name => !KEPT_CACHES.has(name))
                .map(name => caches.delete(name))
        );
        // Take control of all open clients immediately so they
        // use the freshly cached assets instead of stale ones.
        await self.clients.claim();
    })());
});

self.addEventListener('push', (event: PushEvent) => {
    let raw: unknown = null;
    try {
        raw = event.data?.json();
    } catch {
        raw = event.data?.text();
    }
    event.waitUntil(showPushNotification(self.registration, raw));
});

self.addEventListener('notificationclick', (event: NotificationEvent) => {
    event.notification.close();
    const clientsLike = {
        matchAll: (options: { type: 'window'; includeUncontrolled: boolean }) =>
            self.clients.matchAll(options).then((list) => [...list]),
        openWindow: (url: string) => self.clients.openWindow(url).then((win) => win as { postMessage(message: unknown): void } | null),
    };
    event.waitUntil(handleNotificationClick(
        { clients: clientsLike, origin: self.location.origin, basePath: BASE_PATH },
        event.notification.data,
    ));
});

self.addEventListener('sync', (event: SyncEvent) => {
    if (handleClientLogSyncEvent(event)) return;
    if (handleImageUploadSyncEvent(event)) return;
    if (handleEstimateSubmitSyncEvent(event)) return;
});

// ── Story 133 — snapshot freshness ──────────────────────────────────────────

async function postSnapshotMarkDirty(): Promise<void> {
    const clients = await self.clients.matchAll({ type: 'window', includeUncontrolled: true });
    const msg = createSnapshotMarkDirtyMessage();
    for (const client of clients) client.postMessage(msg);
}

async function postSnapshotRefresh(): Promise<void> {
    const clients = await self.clients.matchAll({ type: 'window', includeUncontrolled: true });
    const msg = createSnapshotRefreshMessage();
    for (const client of clients) client.postMessage(msg);
}

/**
 * Periodic Background Sync handler — trigger 4. Post `snapshot:refresh`
 * to all matched clients unconditionally; the client's `refreshIfStale()`
 * does its own cheap `/snapshot/info` check against the local DB's
 * `sync.snapshot_generation` row (which the snapshot import keeps current).
 * The SW deliberately does **not** do that comparison itself — OPFS is
 * unreachable from the SW context, so duplicating the check here would
 * require a parallel IDB store. The cost of "post + client checks" is one
 * cheap GET per tick when nothing changed; periodicsync is hourly+, so
 * this is negligible.
 *
 * If no client is open, posting to zero clients is a no-op and the next
 * tick (or the next app open) picks the work up.
 */
async function handleSnapshotPeriodicSync(): Promise<void> {
    await postSnapshotRefresh();
}

interface SwPeriodicSyncEvent extends ExtendableEvent { tag: string }

self.addEventListener('periodicsync', ((event: SwPeriodicSyncEvent) => {
    if (event.tag !== SNAPSHOT_REFRESH_TAG) return;
    event.waitUntil(handleSnapshotPeriodicSync());
}) as EventListener);

async function registerSnapshotPeriodicSync(): Promise<void> {
    const reg = self.registration as ServiceWorkerRegistration & {
        periodicSync?: {
            register(tag: string, options?: { minInterval?: number }): Promise<void>;
            getTags(): Promise<string[]>;
        };
    };
    if (!reg.periodicSync) return;
    try {
        const tags = await reg.periodicSync.getTags();
        if (tags.includes(SNAPSHOT_REFRESH_TAG)) return;
        await reg.periodicSync.register(SNAPSHOT_REFRESH_TAG, {
            minInterval: SNAPSHOT_REFRESH_MIN_INTERVAL_MS,
        });
    } catch (error) {
        console.error('Failed to register periodic sync', error);
        // Permission may be denied; the other three triggers still cover us.
    }
}

self.addEventListener('activate', (event: ExtendableEvent) => {
    event.waitUntil(registerSnapshotPeriodicSync());
});
