import { shipPendingEstimateSubmits } from './estimate-submit-shipping.js';
import { ESTIMATE_SUBMIT_SYNC_TAG } from './estimate-submit-store.js';

/**
 * SW-side `sync` dispatcher for the estimate-submit queue, mirroring
 * `image-upload-sync-handler.ts`. Returns true when it claimed the event so the
 * SW can chain other sync handlers. Story 221.
 */
export interface EstimateSubmitSyncEventLike {
    readonly tag: string;
    waitUntil(promise: Promise<unknown>): void;
}

export function handleEstimateSubmitSyncEvent(
    event: EstimateSubmitSyncEventLike,
    ship: () => Promise<unknown> = shipPendingEstimateSubmits,
): boolean {
    if (event.tag !== ESTIMATE_SUBMIT_SYNC_TAG) return false;
    event.waitUntil(ship());
    return true;
}
